18	    var value: Double {
19	        switch self {
20	        case .strong: 1.0
21	        case .good: 0.75
22	        case .fair: 0.5
23	        case .poor: 0.25
24	        case .noSignal: 0
25	        }
26	    }
27	    
28	    init(doubleValue: Double) {
29	        if doubleValue >= -60 {
30	            self = .strong
31	        } else if doubleValue < -60 && doubleValue >= -70 {
32	            self = .good
33	        } else if doubleValue < -70 && doubleValue >= -80 {
34	            self = .fair
35	        } else if doubleValue < -80 && doubleValue >= -90 {
36	            self = .poor
37	        } else {
38	            self = .noSignal
39	        }
40	    }
